// ─── AI PROMPT BUILDER ────────────────────────────────────────────
function buildImagePrompt(topic, brandId) {
  const t = topic.toLowerCase();
  const isCapital = brandId === "capital";

  // Capital: deep forest green, premium, no neon
  // Trading: neon green electric glow, high contrast
  const mat = isCapital
    ? "deep forest green and obsidian black materials, premium matte finish, no glow, controlled studio lighting"
    : "neon green #39ff14 electric glow, glossy dark materials, dramatic lighting";

  const suffix = `isolated on pure black background, ultra-realistic 4K CGI render, ${mat}, no text, no watermarks, photorealistic product render`;

  const map = {
    bitcoin:    `3D render of a Bitcoin coin with intricate circuit board etching, ${suffix}`,
    btc:        `3D render of a Bitcoin BTC coin, metallic finish, ${suffix}`,
    ethereum:   `3D render of Ethereum ETH diamond prism, crystalline surfaces, ${suffix}`,
    eth:        `3D render of Ethereum ETH prism shape, ${suffix}`,
    solana:     `3D render of Solana SOL logo coin, geometric precision, ${suffix}`,
    sol:        `3D render of Solana SOL coin with S-logo, ${suffix}`,
    market:     `3D render of a wireframe globe with precision grid lines, latitude longitude detail, ${suffix}`,
    cycle:      `3D render of a high-precision speedometer gauge with arc segments, dark metal body, ${suffix}`,
    bull:       `3D render of a powerful bull sculpture, aggressive stance, ${suffix}`,
    bear:       `3D render of a bear sculpture, dramatic shadow, ${suffix}`,
    rocket:     `3D render of a sleek aerodynamic rocket, glossy fins, ${suffix}`,
    wallet:     `3D render of a premium digital hardware wallet device, ${suffix}`,
    trading:    `3D render of financial candlestick chart bars, metallic precision, ${suffix}`,
    chart:      `3D render of candlestick trading chart, rising candles, ${suffix}`,
    wealth:     `3D render of stacked gold and green bars with coins, luxury, ${suffix}`,
    cashflow:   `3D render of coins flowing in curved arc, abundance symbol, ${suffix}`,
    real_estate:`3D render of a premium architectural model building, ${suffix}`,
    markup:     `3D render of a bold upward arrow, precision geometric form, ${suffix}`,
    markdown:   `3D render of a downward arrow, precision form, ${suffix}`,
    risk:       `3D render of a metallic shield with checkmark emblem, ${suffix}`,
    dca:        `3D render of a calendar with coin stacks, systematic symbol, ${suffix}`,
    blockchain: `3D render of interconnected blockchain cube network, ${suffix}`,
    defi:       `3D render of network nodes with glowing connections, ${suffix}`,
    invest:     `3D render of coin stack with upward growth arrow, ${suffix}`,
    portfolio:  `3D render of multiple asset types in balanced arrangement, ${suffix}`,
    compound:   `3D render of exponential growth spiral with particles, ${suffix}`,
    leverage:   `3D render of precision lever and fulcrum mechanism, ${suffix}`,
    time:       `3D render of an hourglass with flowing particles, ${suffix}`,
  };

  for (const [kw, prompt] of Object.entries(map)) {
    if (t.includes(kw)) return prompt;
  }
  return `Ultra-realistic 3D render representing "${topic}", premium product photography style, ${suffix}`;
}

// ─── CLAUDE SLIDE COPY GENERATION ────────────────────────────────
async function buildSlidesWithAI(concept, brandId, n) {
  const isT = brandId === "trading";
  const innerCount = Math.min(n - 2, 4);

  const system = isT
    ? "You write carousel slide copy for KCE Trading — a crypto/trading education brand. Style: punchy, direct, street-smart. No fluff. Speak to retail traders learning the market. Be specific and actionable."
    : "You write carousel slide copy for KCE Capital — a professional investment brand. Style: authoritative, analytical, institutional. Speak to serious investors building long-term wealth. Be precise and data-aware.";

  const prompt = `Create Instagram carousel slide content for: "${concept}"

Return ONLY valid JSON (no markdown, no explanation):
{
  "coverSub": "punchy 6-8 word subtitle for cover",
  "topLabel": "2-3 word category (e.g. CRYPTO EDUCATION)",
  "caption": "3-4 line Instagram caption, hook first",
  "slides": [
    {"title": "3-5 WORD TITLE IN CAPS", "body": "2 punchy sentences of insight about ${concept}. Specific facts preferred."}
  ],
  "ctaSub": "5-7 word follow CTA subtitle"
}
Generate exactly ${innerCount} slides.`;

  try {
    // Use the Anthropic API — this artifact has built-in access
    const response = await fetch("/api/claude", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "claude-sonnet-4-20250514",
        max_tokens: 1000,
        system,
        messages: [{ role: "user", content: prompt }],
      }),
    });
    if (!response.ok) throw new Error(`Claude API ${response.status}`);
    const data = await response.json();
    const text = data.content?.[0]?.text || "";
    const clean = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(clean);

    const handle = isT ? "@kcetrading" : "@kcecapital";
    const site = isT ? "www.kcetrading.io" : "www.kcecapital.io";

    const slides = [{
      type: "cover",
      topLabel: parsed.topLabel || (isT ? "CRYPTO EDUCATION" : "INVESTMENT INSIGHT"),
      mainWord: concept,
      sub: parsed.coverSub || "Tap to learn more",
      total: n,
    }];
    (parsed.slides || []).slice(0, innerCount).forEach((s, i) => {
      slides.push({ type:"inner", num:i+2, total:n, title:s.title||`POINT ${i+1}`, body:s.body||"" });
    });
    slides.push({ type:"cta", num:n, total:n, title:`Follow ${handle}`, sub:parsed.ctaSub||"Daily insights & analysis", cta:true });

    const caption = `${parsed.caption || `${concept} — everything you need to know 👇`}\n\nFollow ${handle} ${isT?"for daily setups 👊":"for weekly insights 💎"}\n\n${site}`;
    return { slides, caption };

  } catch (err) {
    console.warn("Claude fallback:", err.message);
    const isCapital = brandId === "capital";
    const pts = isCapital
      ? [["THE OPPORTUNITY","The core mechanics and why this matters for long-term wealth building."],
         ["KEY INDICATORS","Critical metrics sophisticated investors track closely."],
         ["STRATEGIC POSITIONING","How to allocate capital intelligently for this opportunity."],
         ["RISK FRAMEWORK","Protect and grow capital with disciplined risk management."]]
      : [["THE SETUP","What's happening in the market right now and why it matters."],
         ["KEY SIGNALS","Critical indicators to watch when analyzing this setup."],
         ["ENTRY STRATEGY","How to position yourself for maximum advantage."],
         ["RISK MANAGEMENT","Protect your capital and manage downside exposure."]];
    const slides = [{ type:"cover", topLabel:isT?"CRYPTO EDUCATION":"INVESTMENT INSIGHT", mainWord:concept, sub:"Tap to learn more", total:n }];
    for (let i = 0; i < Math.min(n-2, pts.length); i++) {
      slides.push({ type:"inner", num:i+2, total:n, title:pts[i][0], body:pts[i][1] });
    }
    slides.push({ type:"cta", num:n, total:n, title:isT?"Follow @kcetrading":"Follow @kcecapital", sub:isT?"Daily setups & market analysis":"Weekly investment insights", cta:true });
    const site = isT ? "www.kcetrading.io" : "www.kcecapital.io";
    const handle = isT ? "@kcetrading" : "@kcecapital";
    return { slides, caption:`${concept} breakdown 👇\n\nFollow ${handle} ${isT?"for daily setups 👊":"for weekly insights 💎"}\n\n${site}` };
  }
}

// ─── SLIDE EXPORT VIA html-to-image ───────────────────────────────
// Best client-side option: html-to-image with pixelRatio:3
// for 3240x3240px output (3x retina = Instagram max quality)
async function exportSlideToBlob(element) {
  // Dynamic import — only loads when needed
  const { toPng } = await import("https://esm.sh/html-to-image@1.11.11");
  const dataUrl = await toPng(element, {
    pixelRatio: 3,        // 3x retina = 3240x3240 from 1080px slide
    quality: 1.0,
    cacheBust: true,
    style: {
      transform: "scale(1)",
      transformOrigin: "top left",
    },
  });
  // Convert dataURL to Blob
  const res = await fetch(dataUrl);
  return res.blob();
}

// ─── CLOUDINARY UPLOAD ────────────────────────────────────────────
async function uploadToCloudinary(blob, cloudName, uploadPreset) {
  const form = new FormData();
  form.append("file", blob);
  form.append("upload_preset", uploadPreset);
  form.append("folder", "kce-hub");
  const res = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, {
    method: "POST",
    body: form,
  });
  if (!res.ok) throw new Error(`Cloudinary upload failed: ${res.status}`);
  const data = await res.json();
  return data.secure_url;
}

// ─── AYRSHARE PUBLISH ─────────────────────────────────────────────
async function publishViaAyrshare(ayrKey, platforms, mediaUrls, caption, scheduleDate) {
  const body = {
    post: caption,
    platforms,
    mediaUrls,
    ...(scheduleDate && { scheduleDate }),
  };
  const res = await fetch("https://app.ayrshare.com/api/post", {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${ayrKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(body),
  });
  if (!res.ok) {
    const e = await res.json();
    throw new Error(e.message || `Ayrshare error ${res.status}`);
  }
  return res.json();
}

