function StepBar({b, steps, current}) {
  return (
    <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:16}}>
      {steps.map((s,i)=>(
        <div key={i} style={{display:"flex",alignItems:"center",flex:1}}>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:3}}>
            <div style={{width:isS=>isS?18:22,height:22,width:22,borderRadius:"50%",
              background:i<current?"#000":i===current?b.accent:"#0a0a0a",
              border:i<current?`1px solid ${b.accent}`:i===current?`2px solid ${b.accent}`:"1px solid #111",
              display:"flex",alignItems:"center",justifyContent:"center",
              fontSize:18,fontWeight:900,
              color:i<current?b.accent:i===current?"#000":"#1a1a1a",
              transition:"all 0.3s"}}>
              {i<current?"✓":i+1}
            </div>
            <div style={{fontSize:16,color:i<=current?b.accent:"#1a1a1a",whiteSpace:"nowrap",fontFamily:"Courier New,monospace",letterSpacing:"0.05em"}}>{s}</div>
          </div>
          {i<steps.length-1 && <div style={{flex:1,height:1,background:i<current?b.accent:"#0a0a0a",margin:"0 3px",marginBottom:14,transition:"all 0.3s"}}/>}
        </div>
      ))}
    </div>
  );
}

// ─── CAROUSEL CONTENT PIPELINE ────────────────────────────────────
function QueueForm({b, title, slides, uploadedImages}) {
  const today = new Date();
  const pad = n => String(n).padStart(2,'0');
  const defaultDate = `${today.getFullYear()}-${pad(today.getMonth()+1)}-${pad(today.getDate()+1)}`;

  const [date, setDate] = useState(defaultDate);
  const [time, setTime] = useState('09:00');
  const [platforms, setPlatforms] = useState(['ig_carousel']);
  const [queued, setQueued] = useState(false);
  const [orderedSlides, setOrderedSlides] = useState(slides.map((s,i)=>({...s})));
  const [caption, setCaption] = useState(`Follow @kcetrading for daily crypto insights 👊\n\nSave this before it disappears 📌\n\nwww.kcetrading.io`);
  const [dragIdx, setDragIdx] = useState(null);
  const [images, setImages] = useState(uploadedImages||[]); // uploaded carousel images

  // sync if parent slides change
  useEffect(() => {
    setOrderedSlides(slides.map(s=>({...s})));
  }, [slides]);

  useEffect(() => {
    if (uploadedImages && uploadedImages.length > 0) setImages(uploadedImages);
  }, [uploadedImages]);

  const togglePlat = (id) => {
    setPlatforms(p => p.includes(id) ? p.filter(x=>x!==id) : [...p, id]);
  };

  const moveSlide = (from, to) => {
    if (to < 0 || to >= orderedSlides.length) return;
    const arr = [...orderedSlides];
    const [moved] = arr.splice(from, 1);
    arr.splice(to, 0, moved);
    setOrderedSlides(arr.map((s,i)=>({...s, num:i+1})));
  };

  const onDragStart = (i) => setDragIdx(i);
  const onDragOver  = (e, i) => { e.preventDefault(); if (dragIdx !== null && dragIdx !== i) moveSlide(dragIdx, i); setDragIdx(i); };
  const onDragEnd   = () => setDragIdx(null);

  const addToQueue = () => {
    if (!title) return;
    const slideText = orderedSlides.map((s,i) => `${i+1}. ${s.text}`).join('\n');
    const fullCaption = `${title}\n\n${slideText}\n\n${caption}`;
    const post = {
      id: 'q_' + Date.now(),
      brand: 'trading',
      type: 'carousel',
      title,
      caption: fullCaption,
      platforms,
      scheduledFor: new Date(date + 'T' + time).toISOString(),
      status: 'scheduled',
      thumbnail: images[0]?.url || images[0] || null,
      images: images.map(i=>i.url||i),
    };
    try {
      const existing = JSON.parse(localStorage.getItem('kce_schedule_posts') || '[]');
      existing.push(post);
      localStorage.setItem('kce_schedule_posts', JSON.stringify(existing));
      setQueued(true);
      setTimeout(() => setQueued(false), 3000);
    } catch(e) {}
  };

  const platOptions = [
    {id:'ig_carousel', label:'IG Carousel', icon:'⊞'},
    {id:'tiktok',      label:'TikTok',      icon:'♪'},
    {id:'twitter_x',   label:'X',           icon:'✕'},
    {id:'facebook',    label:'Facebook',    icon:'f'},
  ];

  const slideTypeLabel = (i, total) => i===0 ? 'HOOK' : i===total-1 ? 'CTA' : 'SLIDE';

  return (
    <div style={{display:'flex', flexDirection:'column', gap:16}}>

      {/* Slide reorder */}
      <div>
        <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginBottom:10, letterSpacing:'0.15em', fontWeight:600, textTransform:'uppercase'}}>REORDER SLIDES — drag or use arrows</div>
        <div style={{display:'flex', flexDirection:'column', gap:6}}>
          {orderedSlides.map((s, i) => (
            <div key={s.num+'-'+i}
              draggable
              onDragStart={()=>onDragStart(i)}
              onDragOver={e=>onDragOver(e,i)}
              onDragEnd={onDragEnd}
              style={{display:'flex', alignItems:'center', gap:10, padding:'10px 12px', borderRadius:8,
                background:dragIdx===i?b.accent+'0d':'rgba(255,255,255,0.02)',
                border:dragIdx===i?`1px solid ${b.accent}`:'1px solid rgba(255,255,255,0.05)',
                cursor:'grab', transition:'all 0.15s'}}>
              <div style={{color:'#333', fontSize:13, cursor:'grab', userSelect:'none'}}>⠿</div>
              <div style={{minWidth:22, height:22, borderRadius:'50%',
                background:i===0||i===orderedSlides.length-1?b.accent:'#111',
                border:i===0||i===orderedSlides.length-1?'none':'1px solid #333',
                display:'flex', alignItems:'center', justifyContent:'center',
                fontSize:12, fontWeight:700,
                color:i===0||i===orderedSlides.length-1?'#000':b.textMuted, flexShrink:0}}>
                {i+1}
              </div>
              <div style={{flex:1, fontSize:14, color:b.textMain}}>{s.text}</div>
              <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginRight:4}}>{slideTypeLabel(i, orderedSlides.length)}</div>
              <div style={{display:'flex', flexDirection:'column', gap:2}}>
                <button onClick={()=>moveSlide(i, i-1)} disabled={i===0}
                  style={{background:'none', border:'none', color:i===0?'#222':b.textMuted, cursor:i===0?'default':'pointer', fontSize:11, padding:'1px 4px', lineHeight:1}}>▲</button>
                <button onClick={()=>moveSlide(i, i+1)} disabled={i===orderedSlides.length-1}
                  style={{background:'none', border:'none', color:i===orderedSlides.length-1?'#222':b.textMuted, cursor:i===orderedSlides.length-1?'default':'pointer', fontSize:11, padding:'1px 4px', lineHeight:1}}>▼</button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Caption */}
      <div>
        <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginBottom:10, letterSpacing:'0.15em', fontWeight:600}}>CAPTION</div>
        <textarea value={caption} onChange={e=>setCaption(e.target.value)} rows={4}
          style={{width:'100%', background:'rgba(255,255,255,0.04)', border:`1px solid ${b.accentBorder}`, borderRadius:10, padding:'12px 14px',
            color:b.textMain, fontSize:14, fontFamily:'inherit', outline:'none',
            resize:'vertical', boxSizing:'border-box', lineHeight:1.7}} />
      </div>

      {/* Image Upload */}
      <div>
        <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginBottom:10, letterSpacing:'0.15em', fontWeight:600}}>CAROUSEL IMAGES ({images.length} added)</div>
        <label style={{display:'block', border:`2px dashed ${b.accentBorder}`, borderRadius:12, padding:'24px', textAlign:'center', cursor:'pointer', transition:'all 0.2s', background:images.length?b.accent+'06':'rgba(0,0,0,0.3)'}}
          onDragOver={e=>{e.preventDefault();e.currentTarget.style.borderColor=b.accent;}}
          onDragLeave={e=>{e.currentTarget.style.borderColor='#222';}}
          onDrop={e=>{
            e.preventDefault();
            e.currentTarget.style.borderColor='#222';
            const files = Array.from(e.dataTransfer.files).filter(f=>f.type.startsWith('image/'));
            files.forEach(f=>{
              const r=new FileReader();
              r.onload=ev=>setImages(prev=>[...prev,ev.target.result]);
              r.readAsDataURL(f);
            });
          }}>
          <input type='file' accept='image/*' multiple style={{display:'none'}} onChange={e=>{
            Array.from(e.target.files).forEach(f=>{
              const r=new FileReader();
              r.onload=ev=>setImages(prev=>[...prev,ev.target.result]);
              r.readAsDataURL(f);
            });
          }} />
          {images.length===0 ? (
            <div>
              <div style={{fontSize:24, marginBottom:6}}>⊞</div>
              <div style={{fontSize:14, color:b.textMuted}}>Drop carousel images here or click to upload</div>
              <div style={{fontSize:12, color:'#333', marginTop:4}}>PNG, JPG — all 8 slides</div>
            </div>
          ) : (
            <div style={{display:'flex', gap:8, flexWrap:'wrap', justifyContent:'center'}}>
              {images.map((img,i)=>(
                <div key={i} style={{position:'relative'}}>
                  <img src={img.url||img} style={{width:64, height:64, objectFit:'cover', borderRadius:6, border:`1px solid ${b.accentBorder}`}} />
                  <button onClick={e=>{e.preventDefault();e.stopPropagation();setImages(prev=>prev.filter((_,idx)=>idx!==i));}}
                    style={{position:'absolute',top:-6,right:-6,width:18,height:18,borderRadius:'50%',background:'#ff4444',border:'none',color:'#fff',fontSize:10,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',lineHeight:1}}>✕</button>
                  <div style={{fontSize:10,color:b.textMuted,textAlign:'center',marginTop:2}}>{i+1}</div>
                </div>
              ))}
              <div style={{display:'flex',alignItems:'center',justifyContent:'center',width:64,height:64,borderRadius:6,border:'1px dashed #333',fontSize:20,color:'#333'}}>+</div>
            </div>
          )}
        </label>
      </div>

      {/* Date + Time */}
      <div style={{display:'flex', gap:12, flexWrap:'wrap'}}>
        <div style={{flex:1, minWidth:140}}>
          <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginBottom:8, letterSpacing:'0.15em', fontWeight:600}}>DATE</div>
          <input type='date' value={date} onChange={e=>setDate(e.target.value)}
            style={{width:'100%', background:'rgba(255,255,255,0.04)', border:`1px solid ${b.accentBorder}`, borderRadius:10, padding:'12px 14px', color:b.textMain, fontSize:14, fontFamily:'inherit', outline:'none', colorScheme:'dark', transition:'border-color 0.2s'}} />
        </div>
        <div style={{flex:1, minWidth:120}}>
          <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginBottom:8, letterSpacing:'0.15em', fontWeight:600}}>TIME</div>
          <input type='time' value={time} onChange={e=>setTime(e.target.value)}
            style={{width:'100%', background:'rgba(255,255,255,0.04)', border:`1px solid ${b.accentBorder}`, borderRadius:10, padding:'12px 14px', color:b.textMain, fontSize:14, fontFamily:'inherit', outline:'none', colorScheme:'dark', transition:'border-color 0.2s'}} />
        </div>
      </div>

      {/* Platforms */}
      <div>
        <div style={{fontSize:11, color:b.textMuted, fontFamily:'Courier New,monospace', marginBottom:10, letterSpacing:'0.15em', fontWeight:600}}>PLATFORMS</div>
        <div style={{display:'flex', gap:8, flexWrap:'wrap'}}>
          {platOptions.map(p => (
            <button key={p.id} onClick={()=>togglePlat(p.id)}
              style={{padding:'7px 14px', borderRadius:8,
                background:platforms.includes(p.id)?b.highlight:'rgba(255,255,255,0.02)',
                border:platforms.includes(p.id)?`1px solid ${b.accentBorder}`:'1px solid rgba(255,255,255,0.06)',
                color:platforms.includes(p.id)?b.accent:'rgba(255,255,255,0.25)',
                fontSize:12, fontFamily:'inherit', cursor:'pointer', fontWeight:platforms.includes(p.id)?600:400}}>
              {p.icon} {p.label}
            </button>
          ))}
        </div>
      </div>

      {/* Submit */}
      <button onClick={addToQueue} disabled={!title || platforms.length===0}
        style={{width:'100%', padding:'16px', borderRadius:10, fontFamily:'inherit', fontWeight:900, fontSize:15,
          background:queued?b.accent+'33':`linear-gradient(135deg,${b.accentSoft}cc,${b.accent}77)`,
          border:queued?`1px solid ${b.accent}`:'none',
          color:'#000', cursor:'pointer', letterSpacing:'0.08em', transition:'all 0.3s',
          boxShadow:b.glow}}>
        {queued ? '✓ ADDED TO QUEUE — CHECK SCHEDULE TAB' : '+ ADD TO QUEUE'}
      </button>
    </div>
  );
}


function CarouselTab({b, keys}) {
  const [idea, setIdea] = useState("");
  const [carouselTitle, setCarouselTitle] = useState("");
  const [slides, setSlides] = useState([]);
  const [expandLoading, setExpandLoading] = useState(false);
  const [sendLoading, setSendLoading] = useState(false);
  const [expandStatus, setExpandStatus] = useState("");
  const [sendStatus, setSendStatus] = useState({msg:"", type:""});
  const [showOutput, setShowOutput] = useState(false);
  const [carouselImages, setCarouselImages] = useState([]);

  const apiKey = keys.openai || "";

  const expandIdea = async () => {
    if (!idea.trim()) { setExpandStatus("Enter an idea first."); return; }
    setExpandLoading(true);
    setExpandStatus("Expanding your idea...");
    setShowOutput(false);
    setSlides([]);
    setCarouselTitle("");

    const systemPrompt = `You are a content writer for KCE Trading, a professional crypto trading brand.

OUTPUT FORMAT (strict — no deviation):
TITLE: [Short title]
SLIDES:
1. [Slide text]
2. [Slide text]
3. [Slide text]
4. [Slide text]
5. [Slide text]
6. [Slide text]
7. [Slide text]
8. [Slide text]

RULES:
- Max 10-12 words per slide
- No paragraphs, no emojis, no fluff
- Confident trading insider tone
- No design instructions, no visual descriptions
- Slide 1: hook
- Slides 2-7: one key insight per slide
- Slide 8: strong CTA or takeaway
- Output only the format above, nothing else`;

    try {
      const res = await fetch("/api/claude", {
        method: "POST",
        headers: {"Content-Type":"application/json"},
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 800,
          system: systemPrompt,
          messages: [{role:"user", content:"IDEA: "+idea.trim()}]
        })
      });
      const data = await res.json();
      if (data.error) { setExpandStatus("Error: "+data.error.message); setExpandLoading(false); return; }
      const text = data.content.map(i=>i.text||"").join("\n").trim();
      const titleMatch = text.match(/TITLE:\s*(.+)/);
      const title = titleMatch ? titleMatch[1].trim() : "";
      const lines = text.split("\n").filter(l=>/^\d+\./.test(l.trim()));
      const parsed = lines.map((l,i)=>({num:i+1, text:l.replace(/^\d+\.\s*/,"").trim()}));
      setCarouselTitle(title);
      setSlides(parsed);
      setShowOutput(true);
      setExpandStatus("");
    } catch(e) {
      setExpandStatus("Error expanding idea. Please try again.");
    }
    setExpandLoading(false);
  };

  const getFormattedContent = () => {
    const title = carouselTitle;
    const slideLines = slides.map(s=>`${s.num}. ${s.text}`).join("\n");
    return `TITLE: ${title}\nSLIDES:\n${slideLines}`;
  };

  const copyContent = () => {
    navigator.clipboard.writeText(getFormattedContent());
  };

  const sendToOpenAI = async () => {
    if (!apiKey) { setSendStatus({msg:"Add your OpenAI API key in Settings to enable slide generation.", type:"warn"}); return; }
    if (slides.length === 0) { setSendStatus({msg:"Expand an idea first.", type:"warn"}); return; }
    setSendLoading(true);
    setSendStatus({msg:"Sending to OpenAI...", type:""});

    const content = getFormattedContent();
    const prompt = `You are a visual carousel designer for KCE Trading, a professional crypto brand.

Apply KCE branding: dark background, neon green accents, glass UI.
Generate a fully designed carousel for the following content:

${content}

Design each slide with proper layout, icons, and styling. Apply KCE brand identity consistently across all slides.`;

    try {
      const res = await fetch("https://api.openai.com/v1/chat/completions", {
        method: "POST",
        headers: {"Content-Type":"application/json","Authorization":"Bearer "+apiKey},
        body: JSON.stringify({
          model: "gpt-4o",
          messages: [{role:"user", content:prompt}],
          max_tokens: 1500
        })
      });
      const data = await res.json();
      if (data.error) {
        setSendStatus({msg:"OpenAI error: "+data.error.message, type:"err"});
      } else {
        setSendStatus({msg:"Sent successfully. OpenAI is generating your slides.", type:"ok"});
      }
    } catch(e) {
      setSendStatus({msg:"Network error. Check your API key and try again.", type:"err"});
    }
    setSendLoading(false);
  };

  const [canvaLoading, setCanvaLoading] = useState(false);
  const [canvaStatus, setCanvaStatus] = useState({msg:"", type:""});

  const sendToCanva = async () => {
    if (slides.length === 0) { setCanvaStatus({msg:"Expand an idea first.", type:"warn"}); return; }
    setCanvaLoading(true);
    setCanvaStatus({msg:"Sending to Canva...", type:""});
    try {
      const payload = {
        title: carouselTitle,
        slide_1: slides[0]?.text || "",
        slide_2: slides[1]?.text || "",
        slide_3: slides[2]?.text || "",
        slide_4: slides[3]?.text || "",
        slide_5: slides[4]?.text || "",
        slide_6: slides[5]?.text || "",
        slide_7: slides[6]?.text || "",
        slide_8: slides[7]?.text || "",
      };
      const res = await fetch("https://hook.us2.make.com/fz2w2l6pxnbudm6l1i9zlse2bsnbw7li", {
        method: "POST",
        headers: {"Content-Type":"application/json"},
        body: JSON.stringify(payload)
      });
      if (res.ok) {
        setCanvaStatus({msg:"✓ Sent to Canva. Check Make.com to see your slides being built.", type:"ok"});
      } else {
        setCanvaStatus({msg:"Error sending to Make.com. Check your webhook URL.", type:"err"});
      }
    } catch(e) {
      setCanvaStatus({msg:"Network error: "+e.message, type:"err"});
    }
    setCanvaLoading(false);
  };

  const statusColor = sendStatus.type==="err" ? "#ff6060" : sendStatus.type==="ok" ? b.accent : b.textMuted;
  const canvaStatusColor = canvaStatus.type==="err" ? "#ff6060" : canvaStatus.type==="ok" ? b.accent : b.textMuted;
  const slideTypes = ["hook","content","content","content","content","content","content","cta"];

  return (
    <div style={{display:"flex", flexDirection:"column", gap:14, animation:"fadeIn 0.3s ease", maxWidth:820}}>

      {/* STEP 1 — Idea input */}
      <Panel b={b} label="STEP 1 — YOUR IDEA">
        <input
          value={idea}
          onChange={e=>setIdea(e.target.value)}
          onKeyDown={e=>{ if(e.key==="Enter") expandIdea(); }}
          placeholder="e.g. Why most traders blow their account in the first 90 days"
          style={{width:"100%", background:"rgba(255,255,255,0.04)", border:idea?`1px solid ${b.accentBorder}`:"1px solid rgba(255,255,255,0.06)", borderRadius:10, padding:"13px 16px", color:b.textMain, fontSize:15, fontFamily:"inherit", outline:"none", boxSizing:"border-box", marginBottom:12, transition:"border-color 0.2s"}}
        />
        <Btn b={b} disabled={!idea.trim()||expandLoading} onClick={expandIdea}
          label={expandLoading ? "⟳ EXPANDING..." : "✦ EXPAND INTO FULL BREAKDOWN"} />
        {expandStatus && (
          <div style={{marginTop:10, fontSize:13, color:expandStatus.includes("Error")||expandStatus.includes("error")?"rgba(255,80,80,0.8)":b.textMuted, textAlign:"center", fontFamily:"Courier New,monospace", letterSpacing:"0.05em"}}>{expandStatus}</div>
        )}
      </Panel>

      {/* UPLOAD FINISHED CAROUSEL IMAGES */}
      <Panel b={b} label="UPLOAD CAROUSEL IMAGES">
        <label style={{display:"block", border:`2px dashed ${carouselImages.length?b.accentBorder:"rgba(255,255,255,0.08)"}`, borderRadius:12, padding:"20px", textAlign:"center", cursor:"pointer", transition:"all 0.2s", background:carouselImages.length?b.highlight:"rgba(255,255,255,0.02)"}}
          onDragOver={e=>{e.preventDefault();e.currentTarget.style.borderColor=b.accent;}}
          onDragLeave={e=>{e.currentTarget.style.borderColor=carouselImages.length?b.accentBorder:"rgba(255,255,255,0.08)";}}
          onDrop={e=>{
            e.preventDefault();
            e.currentTarget.style.borderColor=carouselImages.length?b.accentBorder:"rgba(255,255,255,0.08)";
            Array.from(e.dataTransfer.files).filter(f=>f.type.startsWith("image/")).forEach(f=>{
              const r=new FileReader(); r.onload=ev=>setCarouselImages(prev=>[...prev,{url:ev.target.result,name:f.name}]); r.readAsDataURL(f);
            });
          }}>
          <input type="file" accept="image/*" multiple style={{display:"none"}} onChange={e=>{
            Array.from(e.target.files).forEach(f=>{
              const r=new FileReader(); r.onload=ev=>setCarouselImages(prev=>[...prev,{url:ev.target.result,name:f.name}]); r.readAsDataURL(f);
            });
          }} />
          {carouselImages.length===0 ? (
            <div>
              <div style={{fontSize:28,marginBottom:8,opacity:0.4}}>⊞</div>
              <div style={{fontSize:14,color:b.textSub,marginBottom:4}}>Drop your finished carousel images here</div>
              <div style={{fontSize:12,color:b.textMuted}}>PNG or JPG · all slides · from ChatGPT or Canva</div>
            </div>
          ) : (
            <div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap",justifyContent:"center",marginBottom:10}}>
                {carouselImages.map((img,i)=>(
                  <div key={i} style={{position:"relative"}}>
                    <img src={img.url} style={{width:72,height:72,objectFit:"cover",borderRadius:8,border:`1px solid ${b.accentBorder}`}} />
                    <button onClick={e=>{e.preventDefault();e.stopPropagation();setCarouselImages(prev=>prev.filter((_,idx)=>idx!==i));}}
                      style={{position:"absolute",top:-6,right:-6,width:18,height:18,borderRadius:"50%",background:"rgba(255,60,60,0.9)",border:"none",color:"#fff",fontSize:10,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",lineHeight:1,fontWeight:700}}>✕</button>
                    <div style={{fontSize:10,color:b.textMuted,textAlign:"center",marginTop:3,fontFamily:"Courier New,monospace"}}>{i+1}</div>
                  </div>
                ))}
                <label style={{width:72,height:72,borderRadius:8,border:`1px dashed ${b.accentBorder}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,color:b.textMuted,cursor:"pointer"}}>
                  +
                  <input type="file" accept="image/*" multiple style={{display:"none"}} onChange={e=>{
                    Array.from(e.target.files).forEach(f=>{
                      const r=new FileReader(); r.onload=ev=>setCarouselImages(prev=>[...prev,{url:ev.target.result,name:f.name}]); r.readAsDataURL(f);
                    });
                  }} />
                </label>
              </div>
              <div style={{fontSize:12,color:b.accent,fontFamily:"Courier New,monospace"}}>{carouselImages.length} image{carouselImages.length!==1?"s":""} ready</div>
            </div>
          )}
        </label>
      </Panel>

      {/* STEP 2 — Review & edit */}
      {showOutput && (
        <Panel b={b} label="STEP 2 — EDIT SLIDES">
          {/* Title */}
          <div style={{marginBottom:10}}>
            <div style={{fontSize:11, color:b.textMuted, fontFamily:"Courier New,monospace", marginBottom:8, letterSpacing:"0.15em", fontWeight:600}}>CAROUSEL TITLE</div>
            <input
              value={carouselTitle}
              onChange={e=>setCarouselTitle(e.target.value)}
              style={{width:"100%", background:"rgba(255,255,255,0.04)", border:`1px solid ${b.accentBorder}`, borderRadius:10, padding:"13px 16px", color:b.textMain, fontSize:16, fontWeight:600, fontFamily:"inherit", outline:"none", boxSizing:"border-box", letterSpacing:"0.02em"}}
            />
          </div>
          {/* Slides */}
          <div style={{display:"flex", flexDirection:"column", gap:8}}>
            {slides.map((s,i)=>{
              const type = slideTypes[i]||"content";
              const typeColor = type==="hook"||type==="cta" ? b.accent : b.textMuted;
              const wordCount = s.text.trim().split(/\s+/).filter(Boolean).length;
              const overLimit = wordCount > 12;
              return (
                <div key={i} style={{display:"flex", alignItems:"center", gap:10}}>
                  <div style={{minWidth:26, height:26, borderRadius:8, background:type==="hook"||type==="cta"?b.accent:"rgba(255,255,255,0.04)", border:type==="hook"||type==="cta"?"none":"1px solid rgba(255,255,255,0.08)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:12, color:type==="hook"||type==="cta"?"#020f05":b.textMuted, flexShrink:0, fontWeight:700}}>
                    {s.num}
                  </div>
                  <div style={{flex:1, position:"relative"}}>
                    <input
                      value={s.text}
                      onChange={e=>{const ns=[...slides]; ns[i]={...ns[i],text:e.target.value}; setSlides(ns);}}
                      style={{width:"100%", background:"rgba(255,255,255,0.04)", border:`1px solid ${overLimit?"rgba(255,80,80,0.4)":"rgba(255,255,255,0.07)"}`, borderRadius:8, padding:"11px 44px 11px 14px", color:b.textMain, fontSize:14, fontFamily:"inherit", outline:"none", boxSizing:"border-box", transition:"border-color 0.2s"}}
                    />
                    <span style={{position:"absolute", right:10, top:"50%", transform:"translateY(-50%)", fontSize:10, color:overLimit?"rgba(255,80,80,0.8)":b.textMuted, fontFamily:"Courier New,monospace", pointerEvents:"none"}}>{wordCount}w</span>
                  </div>
                  <div style={{fontSize:10, color:typeColor, width:38, textAlign:"center", flexShrink:0, fontFamily:"Courier New,monospace", letterSpacing:"0.06em", fontWeight:600}}>{type.toUpperCase()}</div>
                  <button onClick={()=>setSlides(slides.filter((_,idx)=>idx!==i).map((s,idx)=>({...s,num:idx+1})))} title="Remove"
                    style={{background:"none", border:"1px solid rgba(255,80,80,0.15)", borderRadius:6, color:"rgba(255,80,80,0.45)", cursor:"pointer", fontSize:11, width:26, height:26, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0}}>✕</button>
                </div>
              );
            })}
          </div>
          <div style={{display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:12, paddingTop:12, borderTop:`1px solid ${b.divider}`}}>
            <button onClick={()=>setSlides(prev=>[...prev, {num:prev.length+1, text:""}])}
              style={{padding:"7px 16px", borderRadius:8, background:b.highlight, border:`1px solid ${b.accentBorder}`, color:b.accent, fontSize:12, fontFamily:"inherit", cursor:"pointer", fontWeight:700, letterSpacing:"0.08em"}}>
              + ADD SLIDE
            </button>
            <span style={{fontSize:11, color:b.textMuted, fontFamily:"Courier New,monospace"}}>{slides.length} slides · max 12w each</span>
          </div>
        </Panel>
      )}

      {/* STEP 3 — Send to Canva */}
      {showOutput && (
        <Panel b={b} label="STEP 3 — SEND TO CANVA">
          <div style={{marginBottom:14}}>
            <Btn b={b} disabled={canvaLoading||slides.length===0} onClick={sendToCanva}
              label={canvaLoading ? "⟳ SENDING TO CANVA..." : "◈ SEND TO CANVA — BUILD SLIDES"} />
            {canvaStatus.msg && (
              <div style={{marginTop:10, fontSize:13, color:canvaStatusColor, textAlign:"center", fontFamily:"Courier New,monospace"}}>{canvaStatus.msg}</div>
            )}
          </div>
        </Panel>
      )}

      {/* STEP 3b — Add to Queue */}
      {showOutput && (
        <Panel b={b} label="STEP 4 — SCHEDULE & QUEUE">
          <QueueForm b={b} title={carouselTitle} slides={slides} uploadedImages={carouselImages} />
        </Panel>
      )}

      {/* STEP 4 — Send to OpenAI (fallback) */}
      {showOutput && (
        <Panel b={b} label="STEP 5 — SEND TO CHATGPT">
          {!apiKey && (
            <div style={{marginBottom:10, padding:"11px 13px", borderRadius:7, background:`${b.accent}07`, border:`1px solid ${b.accentBorder}`, fontSize:14, color:b.accent}}>
              ⚠ Add OpenAI API key in Settings to enable slide generation
            </div>
          )}
          <div style={{display:"flex", gap:12}}>
            <Btn b={b} disabled={sendLoading||slides.length===0||!apiKey} onClick={sendToOpenAI}
              label={sendLoading ? "⟳ SENDING..." : "► SEND TO OPENAI — GENERATE SLIDES"} />
            <button onClick={copyContent}
              style={{padding:"8px 14px", borderRadius:7, background:"transparent", border:`1px solid ${b.cardBorder}`, color:b.textMuted, fontSize:14, fontFamily:"inherit", cursor:"pointer", whiteSpace:"nowrap"}}>
              Copy content
            </button>
            <button onClick={()=>{setIdea("");setShowOutput(false);setSlides([]);setCarouselTitle("");setSendStatus({msg:"",type:""});}}
              style={{padding:"8px 14px", borderRadius:7, background:"transparent", border:`1px solid ${b.cardBorder}`, color:b.textMuted, fontSize:14, fontFamily:"inherit", cursor:"pointer"}}>
              New
            </button>
          </div>
          {sendStatus.msg && (
            <div style={{marginTop:10, fontSize:13, color:statusColor, textAlign:"center", fontFamily:"Courier New,monospace"}}>{sendStatus.msg}</div>
          )}
        </Panel>
      )}
    </div>
  );
}

