function fmtNum(v) {
  const n = parseInt(v);
  if(isNaN(n)||n===0) return "—";
  if(n>=1000000) return (n/1000000).toFixed(1)+"M";
  if(n>=1000)    return (n/1000).toFixed(1)+"K";
  return n.toLocaleString();
}

function fmtPct(v) {
  const n = parseFloat(v);
  return isNaN(n)||n===0 ? "—" : n.toFixed(1)+"%";
}

