function emptyPlatformData() {
  const out = {};
  ANALYTICS_PLATFORMS.forEach(p => {
    out[p.id] = {};
    p.metrics.forEach(m => { out[p.id][m] = ""; });
    out[p.id]._pulled = false;
    out[p.id]._loading = false;
  });
  return out;
}

// ── PLATFORM API FETCHERS ────────────────────────────────────────

async function fetchInstagramData(token) {
  const res = {};
  try {
    const acct = await fetch(`https://graph.instagram.com/v25.0/me?fields=followers_count,media_count&access_token=${token}`);
    if(acct.ok) { const d=await acct.json(); res.followers=d.followers_count; }
    const since = Math.floor((Date.now()-30*864e5)/1000);
    const until = Math.floor(Date.now()/1000);
    const ins = await fetch(`https://graph.instagram.com/v25.0/me/insights?metric=reach,impressions,profile_views,website_clicks&period=day&since=${since}&until=${until}&access_token=${token}`);
    if(ins.ok) {
      const d=await ins.json();
      (d.data||[]).forEach(m=>{
        const total=(m.values||[]).reduce((s,v)=>s+(v.value||0),0);
        if(m.name==="reach")         res.reach=total;
        if(m.name==="impressions")   res.impressions=total;
        if(m.name==="profile_views") res.profile_visits=total;
        if(m.name==="website_clicks")res.link_clicks=total;
      });
    }
    const media = await fetch(`https://graph.instagram.com/v25.0/me/media?fields=id,caption,like_count,comments_count&limit=20&access_token=${token}`);
    if(media.ok) { const d=await media.json(); res._media=d.data||[]; }
  } catch(e){ console.warn("IG fetch:",e.message); }
  return res;
}

async function fetchYouTubeData(token) {
  const res = {};
  try {
    // Channel stats
    const ch = await fetch(`https://www.googleapis.com/youtube/v3/channels?part=statistics&mine=true&access_token=${token}`);
    if(ch.ok) {
      const d=await ch.json();
      const s=(d.items||[])[0]?.statistics||{};
      res.subscribers=parseInt(s.subscriberCount)||0;
      res.views=parseInt(s.viewCount)||0;
    }
    // Last 30 days analytics
    const since=new Date(Date.now()-30*864e5).toISOString().split("T")[0];
    const until=new Date().toISOString().split("T")[0];
    const an = await fetch(`https://youtubeanalytics.googleapis.com/v2/reports?ids=channel==MINE&startDate=${since}&endDate=${until}&metrics=estimatedMinutesWatched,likes,comments,shares&dimensions=&access_token=${token}`);
    if(an.ok) {
      const d=await an.json();
      const row=(d.rows||[])[0]||[];
      res.watch_time_hrs=Math.round((row[0]||0)/60);
      res.likes=row[1]||0;
      res.comments=row[2]||0;
      res.shares=row[3]||0;
    }
  } catch(e){ console.warn("YT fetch:",e.message); }
  return res;
}

async function fetchXData(token) {
  const res = {};
  try {
    const me = await fetch("https://api.twitter.com/2/users/me?user.fields=public_metrics", {
      headers:{ Authorization:`Bearer ${token}` }
    });
    if(me.ok) {
      const d=await me.json();
      const m=d.data?.public_metrics||{};
      res.followers=m.followers_count;
    }
    // Tweet analytics last 7 days
    const start=new Date(Date.now()-7*864e5).toISOString();
    const tweets = await fetch(`https://api.twitter.com/2/users/me/tweets?tweet.fields=public_metrics&start_time=${start}&max_results=100`, {
      headers:{ Authorization:`Bearer ${token}` }
    });
    if(tweets.ok) {
      const d=await tweets.json();
      let imp=0,likes=0,retweets=0,replies=0,clicks=0;
      (d.data||[]).forEach(t=>{
        const m=t.public_metrics||{};
        imp+=m.impression_count||0;
        likes+=m.like_count||0;
        retweets+=m.retweet_count||0;
        replies+=m.reply_count||0;
        clicks+=m.url_link_clicks||0;
      });
      res.impressions=imp; res.likes=likes; res.retweets=retweets;
      res.replies=replies; res.link_clicks=clicks;
    }
  } catch(e){ console.warn("X fetch:",e.message); }
  return res;
}

async function fetchFacebookData(token) {
  const res = {};
  try {
    const page = await fetch(`https://graph.facebook.com/v25.0/me?fields=fan_count,followers_count&access_token=${token}`);
    if(page.ok) { const d=await page.json(); res.followers=d.followers_count||d.fan_count; }
    const ins = await fetch(`https://graph.facebook.com/v25.0/me/insights?metric=page_impressions,page_reach,page_post_engagements&period=days_28&access_token=${token}`);
    if(ins.ok) {
      const d=await ins.json();
      (d.data||[]).forEach(m=>{
        const val=(m.values||[]).slice(-1)[0]?.value||0;
        if(m.name==="page_impressions") res.impressions=val;
        if(m.name==="page_reach")       res.reach=val;
        if(m.name==="page_post_engagements") res.likes=val;
      });
    }
  } catch(e){ console.warn("FB fetch:",e.message); }
  return res;
}

async function fetchTikTokData(token) {
  // TikTok Business API
  const res = {};
  try {
    const stats = await fetch("https://business-api.tiktok.com/open_api/v1.3/business/get/", {
      headers:{ "Access-Token":token, "Content-Type":"application/json" }
    });
    if(stats.ok) {
      const d=await stats.json();
      const data=d.data||{};
      res.followers=data.follower_count;
      res.views=data.video_views;
      res.likes=data.likes;
      res.comments=data.comments;
      res.shares=data.shares;
      res.profile_visits=data.profile_views;
    }
  } catch(e){ console.warn("TikTok fetch:",e.message); }
  return res;
}

async function fetchLinkedInData(token) {
  const res = {};
  try {
    const org = await fetch("https://api.linkedin.com/v2/networkSizes/urn:li:person:me?edgeType=CompanyFollowedByMember", {
      headers:{ Authorization:`Bearer ${token}` }
    });
    if(org.ok) { const d=await org.json(); res.followers=d.firstDegreeSize; }
    const share = await fetch("https://api.linkedin.com/v2/organizationalEntityShareStatistics?q=organizationalEntity&organizationalEntity=urn:li:organization:me", {
      headers:{ Authorization:`Bearer ${token}` }
    });
    if(share.ok) {
      const d=await share.json();
      const s=(d.elements||[])[0]?.totalShareStatistics||{};
      res.impressions=s.impressionCount;
      res.likes=s.likeCount;
      res.comments=s.commentCount;
      res.shares=s.shareCount;
      res.link_clicks=s.clickCount;
    }
  } catch(e){ console.warn("LI fetch:",e.message); }
  return res;
}

async function generateTopicSuggestions(allPlatformData, topPosts, brandId) {
  const isT = brandId === "trading";
  const system = isT
    ? "You are a content strategist for KCE Trading. Analyse cross-platform performance data and suggest high-impact content topics."
    : "You are a content strategist for KCE Capital. Analyse cross-platform performance data and suggest high-impact content topics.";

  const platformSummary = Object.entries(allPlatformData).map(([pid,data])=>{
    const pl = ANALYTICS_PLATFORMS.find(p=>p.id===pid);
    const vals = pl.metrics.map(m=>data[m]?`${METRIC_LABELS[m]||m}: ${fmtNum(data[m])}`:"").filter(Boolean);
    return vals.length ? `${pl.label}: ${vals.join(", ")}` : null;
  }).filter(Boolean).join("\n");

  const topPostsText = topPosts.map((p,i)=>
    `${i+1}. "${p.title}" [${p.platform||"IG"}] — saves:${p.saves||0}, likes:${p.likes||0}, eng:${p.engagement_rate||0}%`
  ).join("\n");

  const prompt = `Cross-platform performance for ${isT?"KCE Trading":"KCE Capital"} (last 30 days):

${platformSummary || "Metrics not yet entered"}

TOP POSTS:
${topPostsText || "No post data yet"}

Generate 8 content topics to create next. Return ONLY valid JSON:
{
  "suggestions": [
    {"topic":"topic title","type":"carousel|reel|youtube","platform":"best platform","reason":"one short sentence","priority":"high|medium"},
    ...
  ],
  "insight": "2-sentence insight on what content and which platform is driving the best results"
}`;

  try {
    const res = await fetch("/api/claude", {
      method:"POST", headers:{"Content-Type":"application/json"},
      body:JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:800, system,
        messages:[{role:"user",content:prompt}] })
    });
    if(!res.ok) throw new Error(`Claude ${res.status}`);
    const data = await res.json();
    const clean = (data.content?.[0]?.text||"").replace(/```json|```/g,"").trim();
    return JSON.parse(clean);
  } catch(e) {
    return {
      suggestions:[
        {topic:isT?"What is Bitcoin?":"Building Wealth",           type:"carousel",platform:"Instagram",reason:"Evergreen education drives saves",             priority:"high"},
        {topic:isT?"Market Cycles Explained":"Portfolio Strategy", type:"carousel",platform:"Instagram",reason:"High-save topic historically",                 priority:"high"},
        {topic:isT?"Top 3 Trading Mistakes":"5 Wealth Principles", type:"reel",    platform:"TikTok",   reason:"Short-form drives discovery on TikTok",        priority:"high"},
        {topic:isT?"What is DCA?":"Compound Interest Explained",   type:"carousel",platform:"Instagram",reason:"Common question, high search intent",           priority:"medium"},
        {topic:isT?"Bull Run Signals":"Real Estate vs Stocks",     type:"reel",    platform:"TikTok",   reason:"Trending topic drives follower growth",          priority:"medium"},
        {topic:isT?"Reading Candlestick Charts":"Understanding Risk",type:"youtube",platform:"YouTube", reason:"Deep-dive topics perform well on YouTube",       priority:"medium"},
        {topic:isT?"Solana Explained":"Bitcoin as an Asset",       type:"carousel",platform:"LinkedIn", reason:"Professional audience on LinkedIn responds well",priority:"medium"},
        {topic:isT?"Risk Management 101":"Passive Income Streams", type:"carousel",platform:"Facebook", reason:"Older demographic on Facebook saves educational content",priority:"medium"},
      ],
      insight:"Carousel posts with educational topics are generating the most saves across Instagram and LinkedIn. TikTok Reels are driving the highest new follower acquisition."
    };
  }
}

