  add("total_likes","likes");
  add("total_comments","comments");
  add("total_saves","saves");
  add("total_shares","shares"); add("total_shares","retweets");
  add("total_link_clicks","link_clicks");

  // ── TOPIC SUGGESTIONS ────────────────────────────────────────────
